# provider_escalation.py — LLM provider escalation for P1 provider incidents
import os, requests
from dataclasses import dataclass

@dataclass
class ProviderStatus:
    provider: str
    status_page_url: str
    support_portal_url: str
    tam_email: str         # Technical Account Manager
    emergency_phone: str   # P1 support line

PROVIDER_CONTACTS: dict[str, ProviderStatus] = {
    'openai': ProviderStatus(
        provider='OpenAI',
        status_page_url='https://status.openai.com',
        support_portal_url='https://help.openai.com',
        tam_email=os.environ.get('OPENAI_TAM_EMAIL', ''),
        emergency_phone=os.environ.get('OPENAI_P1_PHONE', ''),
    ),
    'anthropic': ProviderStatus(
        provider='Anthropic',
        status_page_url='https://status.anthropic.com',
        support_portal_url='https://support.anthropic.com',
        tam_email=os.environ.get('ANTHROPIC_TAM_EMAIL', ''),
        emergency_phone=os.environ.get('ANTHROPIC_P1_PHONE', ''),
    ),
}

def check_provider_status(provider_key: str) -> dict:
    """Fetches the current status from the provider's status page API."""
    provider = PROVIDER_CONTACTS.get(provider_key)
    if not provider:
        raise ValueError(f'Unknown provider: {provider_key}')
    # Most status pages expose a JSON summary endpoint
    summary_url = provider.status_page_url + '/api/v2/summary.json'
    try:
        resp = requests.get(summary_url, timeout=5)
        return resp.json()
    except Exception as e:
        return {'error': str(e), 'provider': provider_key}

def is_provider_incident_active(provider_key: str) -> bool:
    status = check_provider_status(provider_key)
    # status.status.indicator: 'none' = operational, anything else = degraded
    indicator = status.get('status', {}).get('indicator', 'unknown')
    return indicator not in ('none', 'unknown')
